const query = $input.first().json.query || {};
const verifyToken = $env.RIFAH_VERIFY_TOKEN || 'rifah_verify_token_2024';

if (query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === verifyToken) {
  return [{ json: { challenge: query['hub.challenge'], valid: true } }];
}
return [{ json: { challenge: 'ERROR', valid: false } }];

// Parse Meta Cloud API Webhook Payload
const body = $input.first().json.body || $input.first().json;

const entry = body?.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;

// Ignore status updates (delivery receipts etc)
if (value?.statuses && !value?.messages) {
  return [{ json: { skip: true, reason: 'status_update' } }];
}

const messages = value?.messages;
if (!messages || messages.length === 0) {
  return [{ json: { skip: true, reason: 'no_message' } }];
}

const msg = messages[0];
const contact = value?.contacts?.[0];

const extracted = {
  skip: false,
  from: msg.from,
  from_name: contact?.profile?.name || 'Unknown',
  message_id: msg.id,
  timestamp: msg.timestamp,
  type: msg.type,
  text: msg.text?.body || '',
  phone_number_id: value?.metadata?.phone_number_id,
  // Media fields
  image_id: msg.image?.id || null,
  image_mime: msg.image?.mime_type || null,
  document_id: msg.document?.id || null,
  document_filename: msg.document?.filename || null,
  document_mime: msg.document?.mime_type || null,
};

return [{ json: extracted }];

// ============================================================
// RIFAH Connect - Flow 1 State Machine
// ============================================================
const msgNode = $('Extract Message').first().json;
const sessionRaw = $('Get Session').first().json;
const memberRaw = $('Get Member').first().json;

const phone = msgNode.from;
const msgType = msgNode.type || 'text';
const rawText = msgNode.text || '';
const msgText = rawText.trim().toUpperCase();
const rawTextOriginal = rawText.trim();
const hasMedia = ['image', 'document'].includes(msgType);
const mediaId = hasMedia ? (msgNode.image_id || msgNode.document_id) : null;
const mediaFilename = msgNode.document_filename || ('file_' + Date.now());
const mediaMimeType = msgNode.document_mime || 'image/jpeg';

// Parse session
const sessionDocs = sessionRaw?.data || [];
const sessionDoc = sessionDocs.length > 0 ? sessionDocs[0] : {};
let currentStep = sessionDoc.current_step || 'NEW';
let sessionData = {};
try { sessionData = JSON.parse(sessionDoc.session_data || '{}'); } catch(e) {}
const sessionName = sessionDoc.name || null;

// Parse existing member
const memberDocs = memberRaw?.data || [];
const memberExists = memberDocs.length > 0;
const member = memberExists ? memberDocs[0] : null;

let responseMsg = '';
let nextStep = currentStep;
let action = 'none';
let actionData = {};

// ---- HELPER: Main Menu ----
function mainMenu() {
  return `👋 *Welcome to RIFAH Connect!*\n_Connecting 1 Lakh+ Businesses_\n\nPlease select an option:\n\n1️⃣ Register / Update Business\n2️⃣ Find Vendors & Buyers\n3️⃣ Post a Requirement\n4️⃣ My Profile\n5️⃣ Help & Support\n\n_Reply with a number (1-5)_`;
}

// ---- HELPER: Membership Menu ----
function membershipMenu() {
  return `🏷️ *Step 5: Choose Your Membership*\n\n🆓 *FREE TIER (₹0/year)*\n• Manual support\n• 2-3 WhatsApp groups\n• Basic RifahMart listing\n• 24-48 hr response time\n\n⭐ *PREMIUM TIER (₹3,000/year)*\n• 24/7 automated bot\n• 5-10 WhatsApp groups\n• Smart vendor matching\n• Dashboard access\n• Featured RifahMart listing\n• 2-4 hr response time\n\nReply: *FREE* or *PREMIUM*`;
}


// ─── LEAD ID / ADMIN PATTERN DETECTION ──────────────────────────────────────
// ─── LEAD ID PATTERN DETECTION ───────────────────────────────
const leadPattern = /^LEAD-(FREE|PREM)-\d{4}-\d+$/i;
const isLeadId = leadPattern.test(rawTextOriginal.trim());

// Admin command detection (from admin WhatsApp number)
const adminPhone = sessionData._admin_phone || '';
const connectMatch = rawTextOriginal.match(/^CONNECT\s+(\S+)\s+(\S+)/i);
const declineMatch = rawTextOriginal.match(/^DECLINE\s+(\S+)\s+(\S+)/i);
if (connectMatch || declineMatch) {
  const m = connectMatch || declineMatch;
  action = 'admin_approval';
  actionData = {
    command: connectMatch ? 'CONNECT' : 'DECLINE',
    lead_id: m[1],
    vendor_id: m[2],
    admin_phone: phone
  };
  return [{ json: { phone, responseMsg: '', nextStep: currentStep, action, actionData: JSON.stringify(actionData), sessionData: JSON.stringify(sessionData), sessionName, currentStep, shouldSendMsg: false, skip: false } }];
}


switch(currentStep) {

  case 'NEW':
    sessionData = { phone };
    if (memberExists) {
      responseMsg = `👋 Welcome back, *${member.full_name}*!

🪪 Your RIFAH ID: *${member.rifah_id}*
⭐ Membership: ${member.membership_tier}

What would you like to do?

1️⃣ Update my profile
2️⃣ View current info

_Reply 1 or 2_`;
      nextStep = 'EXISTING_CHOICE';
      sessionData.existing_member_id = member.name;
    sessionData.existing_rifah_id = member.rifah_id;
    } else {
      responseMsg = mainMenu();
      nextStep = 'MENU';
    }
    break;

  case 'MENU':
    if (msgText === '1') {
      if (memberExists) {
        responseMsg = `👋 Welcome back, *${member.full_name}*!\n\n🪪 Your RIFAH ID: *${member.rifah_id}*\n⭐ Membership: ${member.membership_tier}\n\nWhat would you like to do?\n\n1️⃣ Update my profile\n2️⃣ View current info\n\n_Reply 1 or 2_`;
        nextStep = 'EXISTING_CHOICE';
        sessionData.existing_member_id = member.name;
        sessionData.existing_rifah_id = member.rifah_id;
      } else {
        responseMsg = `✅ Let's get you registered with RIFAH!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?`;
        nextStep = 'Q1';
      }
    } else if (msgText === '2') {
      if (!memberExists) {
        responseMsg = `⚠️ You need to be a registered RIFAH member to share leads.\n\nReply *1* to register your business first.`;
      } else {
        nextStep = 'LEAD_TYPE';
        if (member.membership_tier === 'PREMIUM' && member.status === 'Active Premium') {
          responseMsg = `⭐ *PREMIUM Share Lead*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* — I need to purchase\n2️⃣ *SELL* — I have products to sell\n3️⃣ *SERVICE NEED* — I need a service\n4️⃣ *SERVICE OFFER* — I provide a service\n\n_Reply: 1, 2, 3, or 4_`;
          sessionData.flow = 'flow2b';
        } else {
          responseMsg = `📋 *Share a Lead (Free)*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* — I need to purchase\n2️⃣ *SELL* — I have products to sell\n3️⃣ *SERVICE NEED* — I need a service\n4️⃣ *SERVICE OFFER* — I provide a service\n\n_Reply: 1, 2, 3, or 4_`;
          sessionData.flow = 'flow2a';
        }
      }
    } else if (msgText === '3') {
      if (!memberExists) {
        responseMsg = `⚠️ You need to be a registered RIFAH member to find leads.\n\nReply *1* to register first.`;
      } else {
        nextStep = 'SEARCH_METHOD';
        const tierNote = (member.membership_tier === 'PREMIUM' && member.status === 'Active Premium')
          ? `\n\n⭐ *Premium Access:* Search all leads across India`
          : `\n\n⚠️ *Free Tier:* Search limited to your industry + city\n💡 Upgrade to Premium for full access`;
        responseMsg = `🔍 *FIND LEAD*\n\nSearch for business opportunities posted by buyers.\n\n*How to search:*\n1️⃣ Browse by Category\n2️⃣ Search by Location\n3️⃣ Browse by Urgency\n4️⃣ View All Recent Leads\n5️⃣ My Saved Searches _(Premium only)_\n6️⃣ My Responses\n0️⃣ Back to Main Menu${tierNote}\n\n_Reply with a number (0-6)_`;
      }
    } else if (['4','5'].includes(msgText)) {
      responseMsg = `🚧 This feature is coming soon!\n\nReply *1* to register your business.`;
    } else {
      if (memberExists) {
        responseMsg = `👋 Welcome back, *${member.full_name}*!

🪪 Your RIFAH ID: *${member.rifah_id}*
⭐ Membership: ${member.membership_tier}

What would you like to do?

1️⃣ Update my profile
2️⃣ View current info

_Reply 1 or 2_`;
        nextStep = 'EXISTING_CHOICE';
        sessionData.existing_member_id = member.name;
    sessionData.existing_rifah_id = member.rifah_id;
      } else {
        responseMsg = mainMenu();
        nextStep = 'MENU';
      }
    }
    break;

  case 'EXISTING_CHOICE':
    if (msgText === '1') {
      responseMsg = `✏️ Let's update your profile!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?\n_(Current: ${member ? member.full_name : 'N/A'})_`;
      nextStep = 'Q1';
      sessionData.is_update = true;
    } else if (msgText === '2') {
      const m = member || {};
      responseMsg = `📋 *Your Current RIFAH Profile*\n\n🪪 ID: *${m.rifah_id || 'N/A'}*\n👤 Name: ${m.full_name || 'N/A'}\n🏢 Business: ${m.business_name || 'N/A'}\n📍 Location: ${m.city_state || 'N/A'}\n🏭 Industry: ${m.industry || 'N/A'}\n⭐ Tier: ${m.membership_tier || 'N/A'}\n📊 Status: ${m.status || 'N/A'}\n🌐 RifahMart: ${m.rifahmart_url || 'Pending'}\n\nReply *1* for main menu.`;
      nextStep = 'MENU';
    } else {
      responseMsg = `Please reply *1* to update profile or *2* to view info.`;
    }
    break;

  case 'Q1':
    if (!rawTextOriginal || rawTextOriginal.length < 2) {
      responseMsg = `❌ Please enter a valid full name.\n\n👤 What is your *full name*?`;
    } else {
      sessionData.full_name = rawTextOriginal;
      responseMsg = `✅ Got it, *${rawTextOriginal}*!\n\n*Question 2 of 6*\n\n🏢 What is your *business name*?`;
      nextStep = 'Q2';
    }
    break;

  case 'Q2':
    if (!rawTextOriginal || rawTextOriginal.length < 2) {
      responseMsg = `❌ Please enter a valid business name.\n\n🏢 What is your *business name*?`;
    } else {
      sessionData.business_name = rawTextOriginal;
      responseMsg = `✅ Got it!\n\n*Question 3 of 6*\n\n📍 Which *city and state* is your business located in?\n\n_Example: Pune, Maharashtra_`;
      nextStep = 'Q3';
    }
    break;

  case 'Q3':
    if (!rawTextOriginal || rawTextOriginal.length < 3) {
      responseMsg = `❌ Please enter your city and state.\n\n📍 Which *city and state* are you in?\n_Example: Pune, Maharashtra_`;
    } else {
      sessionData.city_state = rawTextOriginal;
      responseMsg = `✅ Got it!\n\n*Question 4 of 6*\n\n🏭 What is your *industry / business type*?\n\n_Examples: Manufacturing, Trading, Services, Retail, Export-Import, IT, Healthcare, Food & Beverages_`;
      nextStep = 'Q4';
    }
    break;

  case 'Q4':
    if (!rawTextOriginal || rawTextOriginal.length < 2) {
      responseMsg = `❌ Please enter your industry type.\n\n🏭 What is your *industry / business type*?`;
    } else {
      sessionData.industry = rawTextOriginal;
      responseMsg = `✅ Got it!\n\n*Question 5 of 6*\n\n📅 How many *years* has your business been operating?\n\n_Reply with a number (e.g., 5)_`;
      nextStep = 'Q5';
    }
    break;

  case 'Q5':
    const yearsNum = parseInt(msgText.replace(/[^0-9]/g, ''));
    if (isNaN(yearsNum) || yearsNum < 0 || yearsNum > 200) {
      responseMsg = `❌ Please enter a valid number of years.\n\n📅 How many *years* has your business been operating?`;
    } else {
      sessionData.years_operating = yearsNum;
      responseMsg = `✅ Got it!\n\n*Question 6 of 6*\n\n📱 Please *confirm your WhatsApp number*:\n\n*+${phone}*\n\nReply *YES* to confirm, or type a different number.`;
      nextStep = 'Q6';
    }
    break;

  case 'Q6':
    if (msgText === 'YES' || msgText === 'Y') {
      sessionData.confirmed_phone = phone;
      responseMsg = `✅ Number confirmed: *+${phone}*\n\n📄 *Step 3: Document Verification*\n\nPlease upload your *business verification document*:\n\n• Udyam Registration Certificate\n• OR GST Registration Certificate\n\n_Accepted: PDF, JPG, PNG_`;
      nextStep = 'DOC_UPLOAD';
    } else if (/^[0-9]{10,13}$/.test(msgText.replace(/[^0-9]/g, ''))) {
      sessionData.confirmed_phone = msgText.replace(/[^0-9]/g, '');
      responseMsg = `✅ Using number: *+${sessionData.confirmed_phone}*\n\n📄 *Step 3: Document Verification*\n\nPlease upload your *business verification document*:\n\n• Udyam Registration Certificate\n• OR GST Registration Certificate\n\n_Accepted: PDF, JPG, PNG_`;
      nextStep = 'DOC_UPLOAD';
    } else {
      responseMsg = `Please reply *YES* to confirm +${phone}, or enter your correct 10-digit number.`;
    }
    break;

  case 'DOC_UPLOAD':
    if (hasMedia && mediaId) {
      sessionData.doc_media_id = mediaId;
      sessionData.doc_filename = mediaFilename;
      sessionData.doc_media_type = msgType;
      sessionData.doc_mime = mediaMimeType;
      responseMsg = `✅ Document received!\n\n📦 *Step 4: Product Materials*\n_(Optional but recommended)_\n\nUpload your product materials to attract more buyers:\n\n• Product catalogs (PDF)\n• Product images (JPG/PNG)\n• Brochures / marketing materials\n\n_You can upload multiple files._\n_Reply *SKIP* to skip, or *DONE* when finished uploading._`;
      nextStep = 'PRODUCT_UPLOAD';
      action = 'download_doc';
      actionData = { media_id: mediaId, media_type: msgType, filename: mediaFilename };
    } else {
      responseMsg = `❌ Please upload your document as a file.\n\n📄 Upload your *Udyam Registration* or *GST Certificate* (PDF, JPG, or PNG):`;
    }
    break;

  case 'PRODUCT_UPLOAD':
    const pMaterials = sessionData.product_materials || [];
    if (msgText === 'SKIP' || msgText === 'DONE') {
      sessionData.product_materials = pMaterials;
      responseMsg = membershipMenu();
      nextStep = 'TIER_SELECT';
    } else if (hasMedia && mediaId) {
      pMaterials.push({ media_id: mediaId, type: msgType, filename: mediaFilename });
      sessionData.product_materials = pMaterials;
      const count = pMaterials.length;
      responseMsg = `✅ File ${count} received!\n\nUpload another file, or reply *DONE* when finished.`;
      nextStep = 'PRODUCT_UPLOAD';
      action = 'download_doc';
      actionData = { media_id: mediaId, media_type: msgType, filename: mediaFilename };
    } else {
      responseMsg = `Please upload a product file (PDF/JPG/PNG), or reply *SKIP* to skip / *DONE* if finished.`;
    }
    break;

  case 'TIER_SELECT':
    if (msgText === 'FREE') {
      sessionData.tier = 'FREE';
      responseMsg = '⏳ Processing your registration...';
      nextStep = 'PROCESSING';
      action = 'create_free_member';
      actionData = { ...sessionData };
    } else if (msgText === 'PREMIUM') {
      sessionData.tier = 'PREMIUM';
      responseMsg = `💳 *Premium Membership: ₹3,000/year*\n\nPlease make payment to:\n\n🔸 *UPI ID:* rifah@upi\n🔸 *Bank Transfer:*\n   Account: RIFAH Chamber of Commerce\n   A/C No: 1234567890\n   IFSC: HDFC0001234\n   Bank: HDFC Bank\n\nAfter payment, please:\n📸 Upload *payment screenshot*\nOR\n💬 Send *transaction ID / UTR number*\n\n_We verify within 2 hours._`;
      nextStep = 'PAYMENT_WAIT';
    } else {
      responseMsg = membershipMenu();
    }
    break;

  case 'PAYMENT_WAIT':
    if (hasMedia && mediaId) {
      sessionData.payment_proof_id = mediaId;
      sessionData.payment_type = 'screenshot';
      responseMsg = `✅ Payment screenshot received!\n\n⏳ *Verifying your payment...*\n\nOur team will confirm within *2 hours*.\nYou'll receive a WhatsApp confirmation once verified.\n\nThank you for choosing RIFAH Premium! 🙏`;
      nextStep = 'PAYMENT_PENDING';
      action = 'create_premium_pending';
      actionData = { ...sessionData };
    } else if (rawTextOriginal.length >= 8) {
      sessionData.payment_transaction_id = rawTextOriginal;
      sessionData.payment_type = 'transaction_id';
      responseMsg = `✅ Transaction ID received: *${rawTextOriginal}*\n\n⏳ *Verifying your payment...*\n\nOur team will confirm within *2 hours*.\nYou'll receive a WhatsApp confirmation once verified.\n\nThank you for choosing RIFAH Premium! 🙏`;
      nextStep = 'PAYMENT_PENDING';
      action = 'create_premium_pending';
      actionData = { ...sessionData };
    } else {
      responseMsg = `Please upload your *payment screenshot* or send your *transaction ID / UTR number*.\n\n💳 UPI: rifah@upi`;
    }
    break;

  case 'PAYMENT_PENDING':
    responseMsg = `⏳ Your payment is being verified. You'll receive confirmation shortly.\n\nIf you have questions, contact us directly.`;
    break;

  case 'PROCESSING':
    responseMsg = `⏳ Processing your registration...`;
    break;


  case 'COMPLETED':
    sessionData = { phone };
    if (memberExists) {
      responseMsg = `👋 Welcome back, *${member.full_name}*!

🪪 Your RIFAH ID: *${member.rifah_id}*
⭐ Membership: ${member.membership_tier}

What would you like to do?

1️⃣ Update my profile
2️⃣ View current info

_Reply 1 or 2_`;
      nextStep = 'EXISTING_CHOICE';
      sessionData.existing_member_id = member.name;
      sessionData.existing_rifah_id = member.rifah_id;
    } else {
      responseMsg = mainMenu();
      nextStep = 'MENU';
    }
    break;


  // ─── LEAD COLLECTION STEPS (Free & Premium) ─────────────────────────────
  case 'LEAD_TYPE': {
    const typeMap = { '1':'BUY', '2':'SELL', '3':'SERVICE NEED', '4':'SERVICE OFFER',
                      'BUY':'BUY', 'SELL':'SELL', 'SERVICE NEED':'SERVICE NEED', 'SERVICE OFFER':'SERVICE OFFER' };
    const type = typeMap[msgText] || typeMap[rawTextOriginal.toUpperCase().trim()];
    if (type) {
      sessionData.lead_type = type;
      const emoji = { BUY:'🛒', SELL:'💰', 'SERVICE NEED':'🔧', 'SERVICE OFFER':'🛠️' }[type];
      responseMsg = `✅ Got it! You selected: *${emoji} ${type}*\n\n📝 *Please describe what you need/offer:*\n_(Minimum 10 words)_\n\n*Example:*\n_"Need 5000 plastic bottles, 500ml capacity, food-grade PET material for juice packaging business in Pune"_`;
      nextStep = 'LEAD_DESC';
    } else {
      responseMsg = `📋 *Share Your Requirement*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* - I need to purchase\n2️⃣ *SELL* - I have products to sell\n3️⃣ *SERVICE NEED* - I need a service\n4️⃣ *SERVICE OFFER* - I provide a service\n\n_Reply: BUY, SELL, SERVICE NEED, SERVICE OFFER or 1-4_`;
    }
    break;
  }

  case 'LEAD_DESC': {
    const wordCount = rawTextOriginal.trim().split(/\s+/).filter(w => w.length > 0).length;
    if (wordCount >= 10) {
      sessionData.lead_description = rawTextOriginal.trim();
      responseMsg = `✅ Got it!\n\n📍 *Which city/cities are you looking for?*\n\n*Examples:*\n• Single city: "Pune"\n• Multiple: "Pune, Mumbai, Nashik"\n• State-wide: "Maharashtra"\n• Pan-India: "All India"\n\n_Please specify location:_`;
      nextStep = 'LEAD_LOC';
    } else {
      responseMsg = `⚠️ Please provide more details *(minimum 10 words required)*\n\nYou provided ${wordCount} word${wordCount === 1 ? '' : 's'}. Please describe your requirement in more detail.`;
    }
    break;
  }

  case 'LEAD_LOC': {
    if (rawTextOriginal.trim().length >= 2) {
      sessionData.lead_location = rawTextOriginal.trim();
      responseMsg = `✅ Got it!\n\n⏰ *How urgent is this requirement?*\n\n1️⃣ 🔴 *URGENT* - Need immediately\n2️⃣ 📅 *THIS WEEK* - Within 7 days\n3️⃣ 📆 *THIS MONTH* - Within 30 days\n4️⃣ 🕐 *FLEXIBLE* - No rush\n\n_Reply: URGENT, THIS WEEK, THIS MONTH, FLEXIBLE or 1-4_`;
      nextStep = 'LEAD_URGENCY';
    } else {
      responseMsg = `⚠️ Please enter a valid location (minimum 2 characters).`;
    }
    break;
  }

  case 'LEAD_URGENCY': {
    const urgencyMap = { '1':'URGENT', '2':'THIS WEEK', '3':'THIS MONTH', '4':'FLEXIBLE',
                         'URGENT':'URGENT', 'THIS WEEK':'THIS WEEK', 'THIS MONTH':'THIS MONTH', 'FLEXIBLE':'FLEXIBLE' };
    const urgency = urgencyMap[msgText];
    if (urgency) {
      sessionData.lead_urgency = urgency;
      responseMsg = `✅ Got it!\n\n💰 *What's your budget range?* _(Optional)_\n\n*Examples:*\n• "₹50,000 - ₹1,00,000"\n• "₹5 lakh"\n• "Negotiable"\n\n_Type SKIP to skip this question_`;
      nextStep = 'LEAD_BUDGET';
    } else {
      responseMsg = `⚠️ Please select a valid urgency level.\n\n1️⃣ URGENT\n2️⃣ THIS WEEK\n3️⃣ THIS MONTH\n4️⃣ FLEXIBLE`;
    }
    break;
  }

  case 'LEAD_BUDGET': {
    sessionData.lead_budget = msgText === 'SKIP' ? null : rawTextOriginal.trim();
    sessionData.phone = phone;
    if (!member) {
      responseMsg = `⚠️ You need to be a registered RIFAH member to share leads.\n\nPlease register first by sending *Hi* and selecting *Register*.`;
      nextStep = 'IDLE';
    } else {
      const isPremium = member.membership_tier === 'PREMIUM' && member.status === 'Active Premium';
      sessionData.member_id = member.rifah_id || member.name;
      sessionData.member_name = member.business_name || member.full_name;
      sessionData.is_premium = isPremium;
      action = isPremium ? 'gen_ai_q_prem' : 'gen_ai_q_free';
      actionData = { ...sessionData };
      responseMsg = `🤖 *AI Assistant*\n\nPerfect! Generating smart qualification questions...\n\n⏳ Please wait a moment.`;
      nextStep = 'AI_Q1';
    }
    break;
  }

  case 'AI_Q1':
  case 'AI_Q2':
  case 'AI_Q3':
  case 'AI_Q4':
  case 'AI_Q5':
  case 'AI_Q6': {
    const qNum = parseInt(currentStep.replace('AI_Q',''));
    const wordCount2 = rawTextOriginal.trim().split(/\s+/).filter(w => w.length > 0).length;
    if (wordCount2 < 1) {
      responseMsg = `⚠️ Please provide a valid answer.`;
      break;
    }
    sessionData[`ai_answer_${qNum}`] = rawTextOriginal.trim();

    const aiQuestions = sessionData.ai_questions || [];
    const totalQ = aiQuestions.length;
    const nextQNum = qNum + 1;

    if (nextQNum <= totalQ && aiQuestions[nextQNum - 1]) {
      sessionData[`ai_question_${nextQNum}`] = aiQuestions[nextQNum - 1];
      responseMsg = `✅ Got it!\n\n*Question ${nextQNum} of ${totalQ}:*\n${aiQuestions[nextQNum - 1]}`;
      nextStep = `AI_Q${nextQNum}`;
    } else {
      // All questions answered - route by membership tier
      const isPrem = sessionData.is_premium;
      action = isPrem ? 'create_premium_lead' : 'create_lead';
      actionData = { ...sessionData };
      responseMsg = isPrem
        ? `✅ *All details captured!*\n\n⭐ *PREMIUM Processing:*\n🔍 Searching 1 lakh+ businesses...\n📊 Running smart matching algorithm...\n\n_Results in 5-10 seconds_`
        : `✅ *All details captured!*\n\nCreating your lead... ⏳`;
      nextStep = isPrem ? 'VENDOR_SELECTION' : 'LEAD_CREATE';
    }
    break;
  }

  case 'LEAD_CREATE': {
    // Processing state — show wait message
    responseMsg = `⏳ Still processing your request. Please wait a moment...`;
    break;
  }

  // ── VENDOR FLOW ─────────────────────────────────────────────

  // ─── PREMIUM: VENDOR SELECTION & CONFIRM ────────────────────────────────
  case 'VENDOR_SELECTION': {
    const matchedVendors = sessionData.matched_vendors || [];

    // If no vendors yet — matching is still running or zero results
    if (!matchedVendors.length) {
      responseMsg = `🔍 Still searching for matches... Please wait a moment and try again.`;
      break;
    }

    // Parse selection: "1,2,3" or "1-5" or "ALL"
    let selectedIndices = [];
    const upperMsg2 = rawTextOriginal.trim().toUpperCase();

    if (upperMsg2 === 'ALL') {
      selectedIndices = matchedVendors.map((_, i) => i);
    } else {
      const parts = upperMsg2.split(',');
      for (const part of parts) {
        const trimmed = part.trim();
        const rangeParts = trimmed.split('-');
        if (rangeParts.length === 2 && !isNaN(rangeParts[0]) && !isNaN(rangeParts[1])) {
          const start = parseInt(rangeParts[0]) - 1;
          const end = parseInt(rangeParts[1]) - 1;
          const lo = Math.min(start, end);
          const hi = Math.max(start, end);
          for (let i = lo; i <= hi && i < matchedVendors.length; i++) {
            if (i >= 0) selectedIndices.push(i);
          }
        } else {
          const idx = parseInt(trimmed) - 1;
          if (!isNaN(idx) && idx >= 0 && idx < matchedVendors.length) {
            selectedIndices.push(idx);
          }
        }
      }
      selectedIndices = [...new Set(selectedIndices)]; // deduplicate
    }

    if (!selectedIndices.length) {
      responseMsg = `❌ Invalid selection. Please reply with:\n• Numbers: "1,2,3"\n• Range: "1-5"\n• All: "ALL"\n\nAvailable: 1 to ${matchedVendors.length}`;
      break;
    }

    const selectedVendors = selectedIndices.map(i => matchedVendors[i]);
    sessionData.selected_vendors = selectedVendors;

    const confirmList = selectedVendors.map((v, i) =>
      `${i+1}. ${v.business_name}, ${v.city_state} (Match: ${v.match_score}/100)`
    ).join('\n');

    responseMsg = `✅ You selected *${selectedVendors.length} vendor(s)*:\n\n${confirmList}\n\nProceed? Reply:\n*YES* — Send personalized introductions\n*CHANGE* — Re-select vendors`;
    nextStep = 'VENDOR_CONFIRM';
    break;
  }

  case 'VENDOR_CONFIRM': {
    if (msgText === 'CHANGE') {
      const matchedVendors = sessionData.matched_vendors || [];
      const listMsg = matchedVendors.map((v, i) =>
        `${i+1}. *${v.business_name}*, ${v.city_state}\n   Score: ${v.match_score}/100 | ${v.industry}`
      ).join('\n');
      responseMsg = `📋 *Matched Vendors:*\n\n${listMsg}\n\nReply with numbers (e.g. "1,2,3"), a range (e.g. "1-5"), or "ALL":`;
      nextStep = 'VENDOR_SELECTION';
    } else if (msgText === 'YES') {
      action = 'send_introductions';
      actionData = { selected_vendors: sessionData.selected_vendors || [], lead_id: sessionData.premium_lead_id, phone };
      responseMsg = `⭐ *Sending PREMIUM introductions...*\n\nEach vendor receives a personalized message with your requirements.\nYou'll be notified when vendors respond.\n\n_Introductions being sent now..._`;
      nextStep = 'COMPLETED_BUYER';
    } else {
      responseMsg = `Please reply *YES* to send introductions or *CHANGE* to re-select vendors.`;
    }
    break;
  }

  // ─── VENDOR STEPS (tier-aware) ──────────────────────────────────────────
  case 'VENDOR_INTRO': {
    if (msgText === 'YES') {
      if (!member) {
        responseMsg = `⚠️ *Registration Required*\n\nYou need to be a RIFAH member to respond to leads.\n\nPlease send *Hi* to register.`;
        nextStep = 'IDLE';
      } else {
        action = sessionData.is_premium ? 'gen_vendor_q_prem' : 'gen_vendor_q_free';
        actionData = { ...sessionData, vendor_id: member.rifah_id || member.name, vendor_name: member.business_name || member.full_name, vendor_phone: phone };
        sessionData.vendor_id = member.rifah_id || member.name;
        sessionData.vendor_name = member.business_name || member.full_name;
        responseMsg = `🤖 *Vendor Qualification*\n\nI'll ask 6 quick questions to validate your capability.\n\n⏳ Preparing questions...`;
        nextStep = 'VENDOR_Q1';
      }
    } else {
      responseMsg = `👋 *Interested in this lead?*\n\nReply *YES* to start vendor qualification.\nReply *NO* to skip.`;
      if (msgText === 'NO') { nextStep = 'IDLE'; responseMsg = `No problem! You can respond to other leads anytime.`; }
    }
    break;
  }

  case 'VENDOR_Q1':
  case 'VENDOR_Q2':
  case 'VENDOR_Q3':
  case 'VENDOR_Q4':
  case 'VENDOR_Q5':
  case 'VENDOR_Q6': {
    const vqNum = parseInt(currentStep.replace('VENDOR_Q',''));
    sessionData[`vendor_answer_${vqNum}`] = rawTextOriginal.trim();

    const vendorQs = sessionData.vendor_questions || [];
    const totalVQ = Math.min(vendorQs.length, 6);
    const nextVQ = vqNum + 1;

    if (nextVQ <= totalVQ) {
      const qObj = vendorQs[nextVQ - 1];
      const qText = typeof qObj === 'object' ? qObj.q : qObj;
      const qType = typeof qObj === 'object' ? qObj.type : 'text';
      sessionData[`vendor_question_${nextVQ}`] = qText;
      responseMsg = `✅ Got it!\n\n*Question ${nextVQ} of ${totalVQ}:*\n${qText}\n\n${qType === 'yes_no' ? '_Reply: YES or NO_' : '_Please specify:_'}`;
      nextStep = `VENDOR_Q${nextVQ}`;
    } else {
      // Calculate score
      action = sessionData.is_premium ? 'calc_score_prem' : 'calc_score_free';
      actionData = { ...sessionData };
      responseMsg = `✅ *All questions answered!*\n\nCalculating your compatibility score... 📊`;
      nextStep = 'VENDOR_SCORE';
    }
    break;
  }

  case 'VENDOR_SCORE': {
    if (msgText === 'SUBMIT') {
      action = sessionData.qualification_source === 'flow3' ? 'submit_interest_f3' : (sessionData.is_premium ? 'submit_interest_prem' : 'submit_interest_free');
      actionData = { ...sessionData };
      responseMsg = `⏳ Submitting your interest...`;
      nextStep = 'VENDOR_SUBMIT';
    } else if (msgText === 'CANCEL') {
      responseMsg = `Understood! You can respond to other leads anytime.`;
      nextStep = 'IDLE';
    } else {
      const score = sessionData.compatibility_score || 0;
      const emoji = score >= 80 ? '🌟🌟🌟' : score >= 70 ? '🌟🌟' : score >= 50 ? '🌟' : '⚠️';
      responseMsg = `📊 *Match Analysis*\n\nCompatibility Score: *${score}/100* ${emoji}\n\n${score >= 70 ? '🌟 Excellent match!' : score >= 50 ? '✅ Good fit.' : '⚠️ Low match score.'}\n\nReply *SUBMIT* to express interest\nReply *CANCEL* to skip`;
    }
    break;
  }

  case 'VENDOR_SUBMIT': {
    responseMsg = `⏳ Processing your submission...`;
    break;
  }

  // ─── FLOW 3: FIND LEAD ───────────────────────────────────────────────────

  case 'SEARCH_METHOD': {
    const isPrem3 = member && member.membership_tier === 'PREMIUM' && member.status === 'Active Premium';
    if (msgText === '0' || msgText === 'MENU' || msgText === 'BACK') {
      sessionData = { phone };
      responseMsg = mainMenu();
      nextStep = 'MENU';
    } else if (msgText === '1') {
      action = 'show_categories';
      actionData = { phone, memberId: member?.rifah_id || '', isPremium: isPrem3, industry: member?.industry || '', cityState: member?.city_state || '' };
      responseMsg = `⏳ Loading categories...`;
      nextStep = 'CATEGORY_SELECT';
    } else if (msgText === '2') {
      if (isPrem3) {
        responseMsg = `📍 *SEARCH BY LOCATION*\n\nSelect location scope:\n\n1️⃣ My City (${member.city_state})\n2️⃣ My State\n3️⃣ Type a city name\n4️⃣ All India\n0️⃣ Back\n\n_Reply with a number_`;
        nextStep = 'LOCATION_INPUT';
        sessionData.search_method = 'location';
        sessionData.is_premium = true;
      } else {
        action = 'query_leads_by_location';
        actionData = { phone, location: member?.city_state || '', isPremium: false, memberId: member?.rifah_id || '', industry: member?.industry || '' };
        responseMsg = `📍 Searching leads in *${member?.city_state || 'your city'}*...`;
        nextStep = 'LEAD_SELECT';
        sessionData.search_method = 'location';
        sessionData.is_premium = false;
      }
    } else if (msgText === '3') {
      action = 'show_urgency_options';
      actionData = { phone, memberId: member?.rifah_id || '', isPremium: isPrem3, industry: member?.industry || '', cityState: member?.city_state || '' };
      responseMsg = `⏳ Loading urgency options...`;
      nextStep = 'URGENCY_SELECT';
      sessionData.search_method = 'urgency';
    } else if (msgText === '4') {
      action = 'query_all_recent';
      actionData = { phone, memberId: member?.rifah_id || '', isPremium: isPrem3, industry: member?.industry || '', cityState: member?.city_state || '' };
      responseMsg = `⏳ Loading recent leads...`;
      nextStep = 'LEAD_SELECT';
      sessionData.search_method = 'all_recent';
    } else if (msgText === '5') {
      if (!isPrem3) {
        responseMsg = `⭐ *SAVED SEARCHES*\n\nThis is a Premium feature.\n\nUpgrade to Premium to:\n✓ Save unlimited search filters\n✓ Get daily WhatsApp alerts for new leads\n✓ Quick access to saved searches\n\nReply *UPGRADE* for details or *0* to go back.`;
      } else {
        action = 'my_saved_searches';
        actionData = { phone, memberId: member?.rifah_id || '', searchPreferences: member?.search_preferences || '[]', alertEnabled: member?.daily_alert_enabled || 0 };
        responseMsg = `⏳ Loading your saved searches...`;
        nextStep = 'SEARCH_METHOD';
      }
    } else if (msgText === '6') {
      action = 'my_responses';
      actionData = { phone, memberId: member?.rifah_id || '', rifah_id: member?.rifah_id || '' };
      responseMsg = `⏳ Loading your responses...`;
      nextStep = 'SEARCH_METHOD';
    } else {
      const tierNote2 = (member && member.membership_tier === 'PREMIUM' && member.status === 'Active Premium')
        ? `\n\n⭐ *Premium Access:* Search all leads across India`
        : `\n\n⚠️ *Free Tier:* Search limited to your industry + city`;
      responseMsg = `🔍 *FIND LEAD*\n\n1️⃣ Browse by Category\n2️⃣ Search by Location\n3️⃣ Browse by Urgency\n4️⃣ View All Recent Leads\n5️⃣ My Saved Searches _(Premium only)_\n6️⃣ My Responses\n0️⃣ Back to Main Menu${tierNote2}\n\n_Reply with a number (0-6)_`;
    }
    break;
  }

  case 'CATEGORY_SELECT': {
    const catMap = { '1': 'BUY', '2': 'SELL', '3': 'SERVICE NEED', '4': 'SERVICE OFFER' };
    const cat = catMap[msgText];
    if (msgText === '0' || msgText === 'BACK') {
      action = 'show_find_lead_menu';
      nextStep = 'SEARCH_METHOD';
      responseMsg = '';
    } else if (cat) {
      const isPrem4 = member && member.membership_tier === 'PREMIUM' && member.status === 'Active Premium';
      sessionData.selected_category = cat;
      sessionData.search_method = 'category';
      sessionData.search_offset = 0;
      action = 'query_leads_by_category';
      actionData = { phone, category: cat, isPremium: isPrem4, memberId: member?.rifah_id || '', industry: member?.industry || '', cityState: member?.city_state || '', offset: 0 };
      responseMsg = `⏳ Searching ${cat} leads...`;
      nextStep = 'LEAD_SELECT';
    } else {
      responseMsg = `⚠️ Please reply 1, 2, 3, or 4 to select a category, or 0 to go back.`;
    }
    break;
  }

  case 'URGENCY_SELECT': {
    const urgMap = { '1': 'URGENT', '2': 'THIS WEEK', '3': 'THIS MONTH', '4': 'FLEXIBLE' };
    const urg = urgMap[msgText];
    if (msgText === '0' || msgText === 'BACK') {
      action = 'show_find_lead_menu';
      nextStep = 'SEARCH_METHOD';
      responseMsg = '';
    } else if (urg) {
      const isPrem5 = member && member.membership_tier === 'PREMIUM' && member.status === 'Active Premium';
      sessionData.selected_urgency = urg;
      sessionData.search_offset = 0;
      action = 'query_leads_by_urgency';
      actionData = { phone, urgency: urg, isPremium: isPrem5, memberId: member?.rifah_id || '', industry: member?.industry || '', cityState: member?.city_state || '', offset: 0 };
      responseMsg = `⏳ Searching ${urg} leads...`;
      nextStep = 'LEAD_SELECT';
    } else {
      responseMsg = `⚠️ Please reply 1 (URGENT), 2 (THIS WEEK), 3 (THIS MONTH), or 4 (FLEXIBLE), or 0 to go back.`;
    }
    break;
  }

  case 'LOCATION_INPUT': {
    if (msgText === '0' || msgText === 'BACK') {
      action = 'show_find_lead_menu';
      nextStep = 'SEARCH_METHOD';
      responseMsg = '';
    } else {
      let location = '';
      const isPrem6 = member && member.membership_tier === 'PREMIUM' && member.status === 'Active Premium';
      if (msgText === '1') location = member?.city_state || '';
      else if (msgText === '2') location = (member?.city_state || '').split(',').pop().trim();
      else if (msgText === '4') location = 'All India';
      else location = rawTextOriginal.trim(); // typed city name or option 3
      sessionData.search_location = location;
      sessionData.search_offset = 0;
      action = 'query_leads_by_location';
      actionData = { phone, location, isPremium: isPrem6, memberId: member?.rifah_id || '', industry: member?.industry || '', cityState: member?.city_state || '', offset: 0 };
      responseMsg = `📍 Searching leads in *${location}*...`;
      nextStep = 'LEAD_SELECT';
    }
    break;
  }

  case 'LEAD_SELECT': {
    const sel = parseInt(msgText);
    if (msgText === '0' || msgText === 'BACK') {
      action = 'show_find_lead_menu';
      nextStep = 'SEARCH_METHOD';
      responseMsg = '';
    } else if (msgText === 'MORE') {
      sessionData.search_offset = (sessionData.search_offset || 0) + 20;
      action = 'load_more_leads';
      actionData = { phone, memberId: member?.rifah_id || '', isPremium: member?.membership_tier === 'PREMIUM' && member?.status === 'Active Premium', industry: member?.industry || '', cityState: member?.city_state || '', category: sessionData.selected_category, urgency: sessionData.selected_urgency, location: sessionData.search_location, searchMethod: sessionData.search_method, offset: sessionData.search_offset };
      responseMsg = `⏳ Loading more leads...`;
    } else if (!isNaN(sel) && sel >= 1) {
      sessionData.selected_lead_index = sel - 1;
      action = 'get_lead_detail';
      const isPrem7 = member && member.membership_tier === 'PREMIUM' && member.status === 'Active Premium';
      actionData = { phone, memberId: member?.rifah_id || '', leadIndex: sel - 1, isPremium: isPrem7, leadsRespondedToday: member?.leads_responded_today || 0, lastSearchDate: member?.last_search_date || '' };
      responseMsg = `⏳ Loading lead details...`;
      nextStep = 'LEAD_ACTION';
    } else {
      responseMsg = `⚠️ Please reply with a lead number to view details, *MORE* to see more, or *0* to go back.`;
    }
    break;
  }

  case 'LEAD_ACTION': {
    if (msgText === 'BACK' || msgText === '0') {
      responseMsg = `Reply with a lead number to view, *MORE* for more leads, or *0* to go back to search menu.`;
      nextStep = 'LEAD_SELECT';
    } else if (msgText === 'INTERESTED') {
      const isPrem8 = member && member.membership_tier === 'PREMIUM' && member.status === 'Active Premium';
      const todayStr = new Date().toISOString().split('T')[0];
      const lastDate = member?.last_search_date || '';
      const respondedToday = lastDate === todayStr ? (member?.leads_responded_today || 0) : 0;
      if (!isPrem8 && respondedToday >= 3) {
        responseMsg = `⚠️ *Daily Response Limit Reached*\n\nFree members can respond to 3 leads per day.\n\nYou've used: ${respondedToday}/3\n\n*Upgrade to Premium for:*\n✓ Unlimited lead responses\n✓ Search all industries & locations\n✓ Daily lead alerts\n\nCome back tomorrow or reply *UPGRADE* for details.`;
      } else {
        sessionData.qualification_source = 'flow3';
        sessionData.is_premium = isPrem8;
        action = 'gen_vendor_q_f3';
        actionData = { phone, memberId: member?.rifah_id || '', vendorName: member?.business_name || member?.full_name || '', vendorId: member?.rifah_id || '', isPremium: isPrem8, leadId: sessionData.current_lead_id || '', leadDetails: JSON.stringify(sessionData.current_lead_details || {}), respondedToday };
        responseMsg = `🤖 *Qualification Questions*\n\nGreat! I'll ask 6 quick questions to check your match for this lead.\n\n⏳ Preparing questions...`;
        nextStep = 'VENDOR_Q1';
      }
    } else {
      responseMsg = `Reply *INTERESTED* to respond to this lead, or *BACK* to continue browsing.`;
    }
    break;
  }

  case 'SAVE_SEARCH_NAME': {
    const searchName = rawTextOriginal.trim();
    if (!searchName || msgText === 'CANCEL' || msgText === '0') {
      nextStep = 'SEARCH_METHOD';
      responseMsg = `Search not saved. Reply with a search number to browse leads.`;
    } else {
      action = 'save_search_f3';
      actionData = { phone, memberId: member?.rifah_id || '', searchName, searchCriteria: JSON.stringify({ category: sessionData.selected_category, urgency: sessionData.selected_urgency, location: sessionData.search_location, method: sessionData.search_method }) };
      responseMsg = `✅ Search "*${searchName}*" saved!\n\nWould you like daily alerts for new matching leads?\n\nReply *YES* to enable alerts\nReply *NO* to skip`;
      nextStep = 'SEARCH_METHOD';
    }
    break;
  }

  default: {
    sessionData = { phone };
    responseMsg = mainMenu();
    nextStep = 'MENU';
    break;
  }
}

return [{
  json: {
    phone,
    responseMsg,
    nextStep,
    action,
    actionData: JSON.stringify(actionData),
    sessionData: JSON.stringify(sessionData),
    sessionName,
    currentStep,
    msgType,
    hasMedia,
    mediaId,
    shouldSendMsg: responseMsg.length > 0,
    skip: false
  }
}];

