const leadData = $('Build Premium Lead Data').first().json;
const vendorsRaw = $input.first().json?.data || [];
const leadLocation = (leadData.location || '').toLowerCase();
const leadIndustry = (leadData.lead_type || '').toLowerCase();
const leadDesc = (leadData.description || '').toLowerCase();

// Industry keyword map for related matching
const industryKeywords = {
  'packaging': ['bottle','container','packaging','box','carton','pouch','wrap'],
  'manufacturing': ['machine','equipment','manufacturing','production','fabricat'],
  'food': ['food','beverage','juice','snack','ingredient','grain','spice'],
  'textile': ['fabric','cloth','textile','garment','cotton','yarn','knit'],
  'it': ['software','website','app','development','digital','tech','cloud'],
  'construction': ['construction','building','cement','steel','plumb','electr'],
  'retail': ['retail','shop','store','outlet','wholesale','distribution'],
  'trading': ['trading','export','import','wholesale','supply','procurement']
};

const relatedIndustries = {
  'packaging': ['manufacturing','food','retail'],
  'food': ['packaging','retail','trading'],
  'textile': ['manufacturing','retail','trading'],
  'it': ['services'],
  'construction': ['manufacturing','trading'],
  'retail': ['trading','packaging'],
  'trading': ['manufacturing','retail','packaging']
};

function getIndustryFromDesc(desc) {
  for (const [ind, kws] of Object.entries(industryKeywords)) {
    if (kws.some(k => desc.includes(k))) return ind;
  }
  return '';
}

const detectedLeadIndustry = getIndustryFromDesc(leadDesc);
const cityKeyword = leadLocation.split(',')[0].trim();

const scored = vendorsRaw.map(v => {
  let score = 0;
  const vCity = (v.city_state || '').toLowerCase();
  const vInd = (v.industry || '').toLowerCase();
  const vTier = (v.membership_tier || '').toLowerCase();

  // City match
  if (vCity.includes(cityKeyword) || cityKeyword.includes(vCity.split(',')[0].trim())) score += 30;

  // Industry match
  if (detectedLeadIndustry && vInd.includes(detectedLeadIndustry)) {
    score += 20;
  } else if (detectedLeadIndustry) {
    const related = relatedIndustries[detectedLeadIndustry] || [];
    if (related.some(r => vInd.includes(r))) score += 10;
  }

  // Premium member bonus
  if (vTier === 'premium') score += 5;

  // Experience proxy (use rifah_id year if available)
  const idYear = parseInt((v.rifah_id || '').replace(/\D/g,'').substring(0,4));
  if (!isNaN(idYear)) {
    const exp = Math.max(0, new Date().getFullYear() - idYear);
    score += Math.min(exp, 10);
  }

  return {
    vendor_id: v.rifah_id || v.name,
    business_name: v.business_name || v.full_name || 'Unknown',
    city_state: v.city_state || '',
    industry: v.industry || '',
    tier: v.membership_tier || 'FREE',
    phone: v.whatsapp_number || '',
    match_score: score
  };
}).filter(v => v.match_score >= 40)
  .sort((a,b) => b.match_score - a.match_score)
  .slice(0, 10);

return [{ json: { matched: scored, lead_id: leadData.lead_id, phone: leadData.phone, sd: leadData.sd } }];

const matchData = $('Run Matching Algorithm').first().json;
const matched = matchData.matched || [];
const phone = matchData.phone;
