const sm = $('State Machine').first().json;
let sd = {};
try { sd = JSON.parse(sm.sessionData || '{}'); } catch(e) {}

const answers = [];
for (let i = 1; i <= 6; i++) {
  if (sd[`vendor_answer_${i}`]) answers.push(sd[`vendor_answer_${i}`]);
}

let score = 50;
const questionCount = (sd.vendor_questions || []).length;
const perQ = answers.length > 0 ? Math.floor(40 / Math.min(questionCount, 6)) : 0;

for (const ans of answers) {
  const words = ans.trim().split(/\s+/).length;
  if (words >= 5) score += perQ;
  else if (words >= 2) score += Math.floor(perQ / 2);
}

score = Math.min(score, 100);
sd.compatibility_score = score;

return [{ json: { score, phone: sm.phone, sd: JSON.stringify(sd) } }];

